package main

import (
    "fmt"
    "sync"
)

type Bank struct {
    accounts map[string]float64
    mu       sync.RWMutex
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]float64),
    }
}

func (b *Bank) CreateAccount(accountID string, initialBalance float64) {
    b.mu.Lock()
    defer b.mu.Unlock()
    b.accounts[accountID] = initialBalance
}

func (b *Bank) Deposit(accountID string, amount float64) error {
    if amount < 0 {
        return fmt.Errorf("deposit amount must be positive")
    }
    
    b.mu.Lock()
    defer b.mu.Unlock()
    
    if _, exists := b.accounts[accountID]; !exists {
        return fmt.Errorf("account %s does not exist", accountID)
    }
    
    b.accounts[accountID] += amount
    return nil
}

func (b *Bank) Withdraw(accountID string, amount float64) error {
    if amount < 0 {
        return fmt.Errorf("withdrawal amount must be positive")
    }
    
    b.mu.Lock()
    defer b.mu.Unlock()
    
    if _, exists := b.accounts[accountID]; !exists {
        return fmt.Errorf("account %s does not exist", accountID)
    }
    
    if b.accounts[accountID] < amount {
        return fmt.Errorf("insufficient funds in account %s", accountID)
    }
    
    b.accounts[accountID] -= amount
    return nil
}

func (b *Bank) GetBalance(accountID string) (float64, error) {
    b.mu.RLock()
    defer b.mu.RUnlock()
    
    balance, exists := b.accounts[accountID]
    if !exists {
        return 0, fmt.Errorf("account %s does not exist", accountID)
    }
    
    return balance, nil
}

func (b *Bank) Transfer(fromAccount, toAccount string, amount float64) error {
    if amount < 0 {
        return fmt.Errorf("transfer amount must be positive")
    }
    
    b.mu.Lock()
    defer b.mu.Unlock()
    
    if _, exists := b.accounts[fromAccount]; !exists {
        return fmt.Errorf("account %s does not exist", fromAccount)
    }
    
    if _, exists := b.accounts[toAccount]; !exists {
        return fmt.Errorf("account %s does not exist", toAccount)
    }
    
    if b.accounts[fromAccount] < amount {
        return fmt.Errorf("insufficient funds in account %s", fromAccount)
    }
    
    b.accounts[fromAccount] -= amount
    b.accounts[toAccount] += amount
    return nil
}

